-- Create "user_totp_secrets" table
CREATE TABLE "user_totp_secrets" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "user_id" bigint NOT NULL,
  "secret_ciphertext" bytea NOT NULL,
  "secret_version" character varying NOT NULL DEFAULT 'v1',
  "enabled" boolean NOT NULL DEFAULT false,
  "recovery_code_hashes_json" jsonb NULL,
  "last_used_at" timestamptz NULL,
  PRIMARY KEY ("id")
);
-- Create index "usertotpsecret_enabled_user_id" to table: "user_totp_secrets"
CREATE INDEX "usertotpsecret_enabled_user_id" ON "user_totp_secrets" ("enabled", "user_id");
-- Create index "usertotpsecret_user_id" to table: "user_totp_secrets"
CREATE UNIQUE INDEX "usertotpsecret_user_id" ON "user_totp_secrets" ("user_id");
